/* Fleet switch builder (design.md v2 `switch` component).
 *
 * VENDORED VERBATIM from project-scaffolding. Do NOT edit this file per-app:
 * nothing here varies between apps. Normalized from home-automation, where
 * the same four-line render/update snippet recurs verbatim across lights.js,
 * network-devices.js and network-wifi.js (issue #360) — this file is that
 * snippet, written once.
 *
 * Markup emitted:
 *   <button type="button" class="toggle [on]" role="switch"
 *           aria-checked="true|false" aria-label="...">
 *     <span class="knob"></span><span class="toggle-label">ON|OFF</span>
 *   </button>
 */

'use strict';

/**
 * Build a switch button.
 *
 * @param {boolean} on   initial state.
 * @param {{label?: string, onToggle?: (next: boolean, btn: HTMLButtonElement) => void}} [opts]
 *        `label` becomes the aria-label (name the *thing*, e.g. 'Power Desk lamp').
 *        `onToggle` fires with the *requested* next state; the caller applies it
 *        and calls setSwitch() when the backend confirms (optimistic flips are
 *        the caller's choice, not this builder's).
 * @returns {HTMLButtonElement}
 */
export function switchEl(on, opts) {
  const btn = document.createElement('button');
  btn.type = 'button';
  if (opts && opts.label) btn.setAttribute('aria-label', opts.label);
  btn.setAttribute('role', 'switch');
  setSwitch(btn, on);
  if (opts && opts.onToggle) {
    btn.addEventListener('click', function () {
      opts.onToggle(btn.getAttribute('aria-checked') !== 'true', btn);
    });
  }
  return btn;
}

/**
 * Render a switch's state onto an existing button (build or update — the one
 * write path, so class and aria-checked can never drift apart).
 *
 * @param {HTMLButtonElement} btn  a .toggle button (or one being initialized).
 * @param {boolean} on             the state to render.
 */
export function setSwitch(btn, on) {
  btn.className = 'toggle' + (on ? ' on' : '');
  btn.setAttribute('aria-checked', on ? 'true' : 'false');
  btn.innerHTML = '<span class="knob"></span><span class="toggle-label">' +
    (on ? 'ON' : 'OFF') + '</span>';
}
